import React, { useState } from "react";

const Modal = ({ title, onClose, children }) => (
  <div style={{ position:"fixed", inset:0, background:"#00000077", backdropFilter:"blur(4px)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:200 }}>
    <div style={{ background:"#fff", borderRadius:16, padding:"28px 32px", width:420, boxShadow:"0 24px 60px #00000025", maxHeight:"90vh", overflowY:"auto" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:20 }}>
        <div style={{ fontSize:16, fontWeight:700, color:"#111827" }}>{title}</div>
        <button onClick={onClose} style={{ background:"#f3f4f6", border:"none", borderRadius:6, width:28, height:28, cursor:"pointer", fontSize:16, color:"#6b7280" }}>x</button>
      </div>
      {children}
    </div>
  </div>
);

const Field = ({ label, value, onChange, placeholder, type="text" }) => (
  <div style={{ marginBottom:14 }}>
    <div style={{ fontSize:11, fontWeight:600, color:"#374151", marginBottom:5 }}>{label}</div>
    <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
      style={{ width:"100%", padding:"9px 12px", border:"1px solid #e5e7eb", borderRadius:8, fontSize:13, outline:"none", fontFamily:"monospace", boxSizing:"border-box", background:"#f9fafb", color:"#111827" }} />
  </div>
);

const Select = ({ label, value, onChange, options }) => (
  <div style={{ marginBottom:14 }}>
    <div style={{ fontSize:11, fontWeight:600, color:"#374151", marginBottom:5 }}>{label}</div>
    <select value={value} onChange={e=>onChange(e.target.value)}
      style={{ width:"100%", padding:"9px 12px", border:"1px solid #e5e7eb", borderRadius:8, fontSize:13, outline:"none", fontFamily:"monospace", boxSizing:"border-box", background:"#f9fafb", color:"#111827" }}>
      {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
    </select>
  </div>
);

const ApplyBtn = ({ onClick, label="Apply" }) => (
  <div style={{ display:"flex", justifyContent:"flex-end", gap:10, marginTop:20 }}>
    <button onClick={onClick} style={{ background:"#1d4ed8", border:"none", color:"#fff", padding:"10px 24px", borderRadius:8, cursor:"pointer", fontSize:13, fontWeight:700 }}>{label}</button>
  </div>
);

const InfoBox = ({ text }) => (
  <div style={{ background:"#eff6ff", border:"1px solid #bfdbfe", borderRadius:8, padding:"10px 14px", fontSize:11, color:"#1e40af", marginBottom:16 }}>{text}</div>
);

const interfaces = ["GigabitEthernet0/0","GigabitEthernet0/1","GigabitEthernet0/2","GigabitEthernet0/3","Vlan1"];

// ??? MODALS ???
const IPModal = ({ onClose, onCommand }) => {
  const [iface, setIface] = useState("GigabitEthernet0/0");
  const [ip, setIp] = useState("");
  const [mask, setMask] = useState("255.255.255.0");
  const apply = () => {
    if (!ip) return;
    onCommand("configure terminal");
    setTimeout(() => { onCommand(`interface ${iface}`);
    setTimeout(() => { onCommand(`ip address ${ip} ${mask}`);
    setTimeout(() => { onCommand("no shutdown");
    setTimeout(() => onCommand("end"), 200); }, 200); }, 200); }, 200);
    onClose();
  };
  return (
    <Modal title="Set IP Address" onClose={onClose}>
      <InfoBox text="Assign an IP address to a network interface." />
      <Select label="Interface" value={iface} onChange={setIface} options={interfaces.map(i=>({value:i,label:i}))} />
      <Field label="IP Address" value={ip} onChange={setIp} placeholder="e.g. 192.168.1.1" />
      <Field label="Subnet Mask" value={mask} onChange={setMask} placeholder="e.g. 255.255.255.0" />
      <ApplyBtn onClick={apply} label="Assign IP" />
    </Modal>
  );
};

const PortModal = ({ onClose, onCommand }) => {
  const [iface, setIface] = useState("GigabitEthernet0/1");
  const [action, setAction] = useState("enable");
  const apply = () => {
    onCommand("configure terminal");
    setTimeout(() => { onCommand(`interface ${iface}`);
    setTimeout(() => { onCommand(action==="enable"?"no shutdown":"shutdown");
    setTimeout(() => onCommand("end"), 200); }, 200); }, 200);
    onClose();
  };
  return (
    <Modal title="Enable / Disable Port" onClose={onClose}>
      <InfoBox text="Control the administrative state of a port." />
      <Select label="Interface" value={iface} onChange={setIface} options={interfaces.map(i=>({value:i,label:i}))} />
      <Select label="Action" value={action} onChange={setAction} options={[{value:"enable",label:"Enable Port (no shutdown)"},{value:"disable",label:"Disable Port (shutdown)"}]} />
      <ApplyBtn onClick={apply} label="Apply" />
    </Modal>
  );
};

const VLANModal = ({ onClose, onCommand }) => {
  const [vlanId, setVlanId] = useState("");
  const [vlanName, setVlanName] = useState("");
  const [iface, setIface] = useState("GigabitEthernet0/1");
  const [mode, setMode] = useState("access");
  const apply = () => {
    if (!vlanId) return;
    onCommand("configure terminal");
    setTimeout(() => { onCommand(`vlan ${vlanId}`);
    setTimeout(() => { if(vlanName) onCommand(`name ${vlanName}`);
    setTimeout(() => { onCommand("exit");
    setTimeout(() => { onCommand(`interface ${iface}`);
    setTimeout(() => { onCommand(`switchport mode ${mode}`);
    setTimeout(() => { onCommand(`switchport access vlan ${vlanId}`);
    setTimeout(() => onCommand("end"), 200); }, 200); }, 200); }, 200); }, 200); }, 200); }, 200);
    onClose();
  };
  return (
    <Modal title="Configure VLAN" onClose={onClose}>
      <InfoBox text="Create a VLAN and assign it to an interface." />
      <Field label="VLAN ID" value={vlanId} onChange={setVlanId} placeholder="e.g. 10" />
      <Field label="VLAN Name (optional)" value={vlanName} onChange={setVlanName} placeholder="e.g. Management" />
      <Select label="Interface" value={iface} onChange={setIface} options={interfaces.map(i=>({value:i,label:i}))} />
      <Select label="Port Mode" value={mode} onChange={setMode} options={[{value:"access",label:"Access"},{value:"trunk",label:"Trunk"}]} />
      <ApplyBtn onClick={apply} label="Create VLAN" />
    </Modal>
  );
};

const HostnameModal = ({ onClose, onCommand }) => {
  const [name, setName] = useState("");
  const apply = () => {
    if (!name) return;
    onCommand("configure terminal");
    setTimeout(() => { onCommand(`hostname ${name}`);
    setTimeout(() => onCommand("end"), 200); }, 200);
    onClose();
  };
  return (
    <Modal title="Change Hostname" onClose={onClose}>
      <InfoBox text="Set a custom name for the network device." />
      <Field label="New Hostname" value={name} onChange={setName} placeholder="e.g. CoreSwitch" />
      <ApplyBtn onClick={apply} label="Change" />
    </Modal>
  );
};

const SaveModal = ({ onClose, onCommand }) => {
  const apply = () => { onCommand("write memory"); onClose(); };
  return (
    <Modal title="Save Configuration" onClose={onClose}>
      <InfoBox text="Save the running configuration to NVRAM (startup-config)." />
      <div style={{ fontSize:13, color:"#374151", marginBottom:16 }}>This will execute: <span style={{ fontFamily:"monospace", background:"#f3f4f6", padding:"2px 8px", borderRadius:4 }}>write memory</span></div>
      <ApplyBtn onClick={apply} label="Save Now" />
    </Modal>
  );
};

const ShowModal = ({ onClose, onCommand }) => {
  const [cmd, setCmd] = useState("show ip interface brief");
  const cmds = [
    { value:"show ip interface brief", label:"Interface Status" },
    { value:"show running-config", label:"Running Config" },
    { value:"show version", label:"IOS Version" },
    { value:"show vlan brief", label:"VLAN Table" },
    { value:"show interfaces", label:"All Interfaces Detail" },
  ];
  const apply = () => { onCommand(cmd); onClose(); };
  return (
    <Modal title="Show Network Status" onClose={onClose}>
      <InfoBox text="Display current network information." />
      <Select label="What to show?" value={cmd} onChange={setCmd} options={cmds} />
      <ApplyBtn onClick={apply} label="Show" />
    </Modal>
  );
};

const BannerModal = ({ onClose, onCommand }) => {
  const [msg, setMsg] = useState("");
  const apply = () => {
    if (!msg) return;
    onCommand("configure terminal");
    setTimeout(() => { onCommand(`banner motd # ${msg} #`);
    setTimeout(() => onCommand("end"), 200); }, 200);
    onClose();
  };
  return (
    <Modal title="Set Login Banner" onClose={onClose}>
      <InfoBox text="Set a message that appears when users log in." />
      <Field label="Banner Message" value={msg} onChange={setMsg} placeholder="e.g. Authorized Access Only" />
      <ApplyBtn onClick={apply} label="Set Banner" />
    </Modal>
  );
};

const PasswordModal = ({ onClose, onCommand }) => {
  const [pass, setPass] = useState("");
  const [type, setType] = useState("enable");
  const apply = () => {
    if (!pass) return;
    onCommand("configure terminal");
    setTimeout(() => {
      if (type==="enable") { onCommand(`enable secret ${pass}`); }
      else { onCommand("line console 0"); setTimeout(() => { onCommand(`password ${pass}`); setTimeout(() => { onCommand("login"); setTimeout(() => onCommand("end"), 200); }, 200); }, 200); return; }
      setTimeout(() => onCommand("end"), 200);
    }, 200);
    onClose();
  };
  return (
    <Modal title="Set Password" onClose={onClose}>
      <InfoBox text="Configure device access passwords." />
      <Select label="Password Type" value={type} onChange={setType} options={[{value:"enable",label:"Enable Secret (Privileged)"},{value:"console",label:"Console Password"}]} />
      <Field label="Password" value={pass} onChange={setPass} placeholder="Enter password" type="password" />
      <ApplyBtn onClick={apply} label="Set Password" />
    </Modal>
  );
};

const StaticRouteModal = ({ onClose, onCommand }) => {
  const [network, setNetwork] = useState("");
  const [mask, setMask] = useState("255.255.255.0");
  const [next, setNext] = useState("");
  const apply = () => {
    if (!network||!next) return;
    onCommand("configure terminal");
    setTimeout(() => { onCommand(`ip route ${network} ${mask} ${next}`);
    setTimeout(() => onCommand("end"), 200); }, 200);
    onClose();
  };
  return (
    <Modal title="Add Static Route" onClose={onClose}>
      <InfoBox text="Add a static route to the routing table." />
      <Field label="Destination Network" value={network} onChange={setNetwork} placeholder="e.g. 192.168.2.0" />
      <Field label="Subnet Mask" value={mask} onChange={setMask} placeholder="e.g. 255.255.255.0" />
      <Field label="Next Hop (Gateway)" value={next} onChange={setNext} placeholder="e.g. 192.168.1.254" />
      <ApplyBtn onClick={apply} label="Add Route" />
    </Modal>
  );
};

